'use client';

import React from 'react';
import { motion } from 'framer-motion';
import Link from 'next/link';
import GlassCard from '@/components/ui/glassCard';
import ProgressBar from '@/components/ui/progressBar';
import { useAppStore } from '@/store/useAppStore';
import { useAuthStore } from '@/store/useAuthStore';
import { curriculum } from '@/data/curriculum';
import { HTMLMascot, CSSMascot, JSMascot, PHPMascot, MySQLMascot, StreakFire } from '@/components/illustrations/mascots';
import AuthGuard from '@/components/auth/authGuard';
import { useT } from '@/store/useLanguageStore';
import DailyQuest from '@/components/quest/dailyQuest';
import { useIsMobile } from '@/hooks/useIsMobile';

const langColors: Record<string, string> = {
    html: '#F06D5B',
    css: '#7EB8F0',
    js: '#F5C87A',
    php: '#9B8FE6',
    mysql: '#3B82F6',
};

const langMascots: Record<string, React.FC<{ size?: number; animate?: boolean }>> = {
    html: HTMLMascot,
    css: CSSMascot,
    js: JSMascot,
    php: PHPMascot,
    mysql: MySQLMascot,
};

function EducationContent() {
    const { userName, streak, progress, failedAnswers } = useAppStore();
    const { user, logout } = useAuthStore();
    const t = useT();
    const isMobile = useIsMobile();

    return (
        <div className="space-y-8">
            {/* Top Bar */}
            <motion.div
                className="flex items-center justify-between"
                initial={isMobile ? { opacity: 1, y: 0 } : { opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ type: 'spring', stiffness: 300, damping: 25 }}
            >
                <Link
                    href="/"
                    className="inline-flex items-center gap-2 px-4 py-2 rounded-[var(--radius-button)] glass soft-shadow text-sm font-medium text-text-secondary hover:text-text transition-colors"
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                        <path d="M19 12H5M12 19L5 12L12 5" />
                    </svg>
                    {t('common.backHome')}
                </Link>

                <Link
                    href="/profile"
                    className="inline-flex items-center gap-2 px-4 py-2 rounded-[var(--radius-button)] glass soft-shadow text-sm font-medium text-text-secondary hover:text-text transition-colors"
                >
                    <div className="w-6 h-6 rounded-lg bg-primary/20 flex items-center justify-center text-xs font-bold text-primary">
                        {(user?.name || userName || 'L').charAt(0).toUpperCase()}
                    </div>
                    {user?.name || userName || 'Profile'}
                </Link>
            </motion.div>

            {/* Hero */}
            <motion.div
                className="text-center lg:text-left"
                initial={isMobile ? { opacity: 1, y: 0 } : { opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ type: 'spring', stiffness: 300, damping: 24 }}
            >
                <h1 className="text-3xl lg:text-4xl font-extrabold text-text">
                    Hello, <span className="text-gradient">{user?.name || userName}</span>!
                </h1>
                <p className="text-text-secondary mt-2 text-lg">
                    {t('edu.readyToLearn')}
                </p>

                {streak > 0 && (
                    <motion.div
                        className="inline-flex items-center gap-2 mt-3 px-4 py-2 bg-warning/15 rounded-full"
                        initial={isMobile ? { scale: 1 } : { scale: 0 }}
                        animate={{ scale: 1 }}
                        transition={{ type: 'spring', stiffness: 400, damping: 15, delay: isMobile ? 0 : 0.3 }}
                    >
                        <StreakFire size={28} days={streak} />
                        <span className="text-sm font-semibold text-text">{streak} {t('edu.dayStreak')}</span>
                    </motion.div>
                )}
            </motion.div>

            {/* Daily Quest */}
            <DailyQuest />

            {/* Dedicated Pet Link */}
            <Link href="/pet" className="block mb-4">
                <GlassCard hoverable className="flex items-center gap-4 py-4 px-5">
                    <div className="w-12 h-12 bg-primary/10 rounded-2xl flex items-center justify-center shrink-0">
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--color-primary)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M12 21a9 9 0 0 0 9-9c0-3.5-2-6.5-5-8M12 21a9 9 0 0 1-9-9c0-3.5 2-6.5 5-8" />
                            <path d="M15 7c-2-2-4-2-6 0M10 12h.01M14 12h.01" />
                            <path d="M12 16c-.5 0-1.5-.5-1.5-1h3c0 .5-1 1-1.5 1z" />
                        </svg>
                    </div>
                    <div className="flex-1">
                        <h3 className="text-lg font-bold text-text mb-0.5">Kunjungi Companion Kamu</h3>
                        <p className="text-sm text-text-secondary">Pelihara, beri makan, dan pakaikan aksesoris!</p>
                    </div>
                    <div className="w-8 h-8 rounded-full bg-white/50 dark:bg-slate-700/50 flex items-center justify-center text-text-secondary dark:text-slate-300">
                        →
                    </div>
                </GlassCard>
            </Link>

            {/* Official Language Cards */}
            <div className="space-y-3">
                <h2 className="text-lg font-bold text-text">{t('edu.choosePath')}</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {Object.values(curriculum).map((lang, i) => {
                        const langProgress = progress[lang.id as keyof typeof progress];
                        const MascotComponent = langMascots[lang.id];
                        return (
                            <Link key={lang.id} href={`/learn/${lang.id}`}>
                                <GlassCard hoverable delay={i * 0.08} className="h-full">
                                    <div className="flex items-start gap-4">
                                        <motion.div
                                            className="shrink-0"
                                            whileHover={isMobile ? {} : { rotate: 5, scale: 1.05 }}
                                        >
                                            {MascotComponent && <MascotComponent size={56} animate={!isMobile} />}
                                        </motion.div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-1">
                                                <h3 className="text-lg font-bold" style={{ color: langColors[lang.id] }}>
                                                    {lang.name}
                                                </h3>
                                                <span className="text-xs text-text-secondary dark:text-slate-300 bg-white/50 dark:bg-slate-800 px-2 py-0.5 rounded-full">
                                                    {lang.levels.length} {t('common.levels')}
                                                </span>
                                            </div>
                                            <p className="text-sm text-text-secondary mb-3">{lang.description}</p>
                                            <ProgressBar
                                                progress={langProgress?.overallProgress || 0}
                                                color={langColors[lang.id]}
                                                height={8}
                                                showLabel
                                            />
                                        </div>
                                    </div>
                                </GlassCard>
                            </Link>
                        );
                    })}
                </div>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-3 gap-3">
                {[
                    {
                        label: t('edu.streak'),
                        value: `${streak}`,
                        stat: 'streak' as const,
                        bg: 'rgba(245, 200, 122, 0.1)',
                    },
                    {
                        label: t('edu.completed'),
                        value: `${Object.values(progress).reduce((acc, p) => acc + Object.keys(p.completedLevels).length, 0)}`,
                        stat: 'completed' as const,
                        bg: 'rgba(140, 215, 144, 0.1)',
                    },
                    {
                        label: t('edu.languages'),
                        value: `${Object.values(progress).filter(p => Object.keys(p.completedLevels).length > 0).length}/5`,
                        stat: 'languages' as const,
                        bg: 'rgba(126, 184, 240, 0.1)',
                    },
                ].map((stat, i) => (
                    <GlassCard key={stat.label} delay={0.4 + i * 0.08}>
                        <div className="text-center">
                            <motion.div
                                className="w-10 h-10 rounded-xl flex items-center justify-center mx-auto mb-2"
                                style={{ background: stat.bg }}
                                animate={isMobile ? {} : { scale: [1, 1.05, 1] }}
                                transition={{ duration: 2, repeat: Infinity, delay: i * 0.3 }}
                            >
                                {stat.stat === 'streak' && <StreakFire size={24} days={0} />}
                                {stat.stat === 'completed' && (
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                                        <circle cx="12" cy="12" r="10" fill="#8CD790" />
                                        <path d="M8 12 L11 15 L16 9" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                    </svg>
                                )}
                                {stat.stat === 'languages' && (
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                                        <circle cx="12" cy="12" r="10" fill="#7EB8F0" />
                                        <circle cx="9" cy="10" r="2.5" fill="white" opacity="0.8" />
                                        <circle cx="15" cy="10" r="2.5" fill="white" opacity="0.8" />
                                        <circle cx="12" cy="16" r="2.5" fill="white" opacity="0.8" />
                                    </svg>
                                )}
                            </motion.div>
                            <div className="text-xl font-bold text-text">{stat.value}</div>
                            <div className="text-xs text-text-secondary">{stat.label}</div>
                        </div>
                    </GlassCard>
                ))}
            </div>

            {/* Failed Answers Stats */}
            {(failedAnswers.html + failedAnswers.css + failedAnswers.js + failedAnswers.php + (failedAnswers.mysql || 0)) > 0 && (
                <GlassCard delay={0.55}>
                    <div className="flex items-center gap-2 mb-4">
                        <div className="w-8 h-8 rounded-xl bg-error/10 flex items-center justify-center">
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                                <circle cx="12" cy="12" r="10" fill="#F06D5B" opacity="0.8" />
                                <path d="M15 9L9 15M9 9L15 15" stroke="white" strokeWidth="2" strokeLinecap="round" />
                            </svg>
                        </div>
                        <h3 className="text-sm font-bold text-text">{t('edu.failedAnswers')}</h3>
                    </div>
                    <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
                        {([
                            { key: 'html', label: 'HTML', color: '#F06D5B' },
                            { key: 'css', label: 'CSS', color: '#7EB8F0' },
                            { key: 'js', label: 'JS', color: '#F5C87A' },
                            { key: 'php', label: 'PHP', color: '#9B8FE6' },
                            { key: 'mysql', label: 'DB', color: '#3B82F6' },
                        ] as const).map((lang) => {
                            const initProps: any = isMobile ? { scale: 1 } : { scale: 0 };
                            return (
                                <motion.div
                                    key={lang.key}
                                    className="text-center p-2 rounded-xl bg-white/30 dark:bg-slate-800/50"
                                    initial={initProps}
                                    animate={{ scale: 1 }}
                                    transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                                >
                                    <div className="text-lg font-bold" style={{ color: lang.color }}>
                                        {failedAnswers[lang.key] || 0}
                                    </div>
                                    <div className="text-[10px] font-semibold text-text-secondary">{lang.label}</div>
                                </motion.div>
                            );
                        })}
                    </div>
                </GlassCard>
            )}

            {/* Sign out link */}
            <div className="text-center pt-4">
                <button
                    onClick={() => logout()}
                    className="text-xs text-text-secondary hover:text-error transition-colors cursor-pointer"
                >
                    {t('common.signOut')}
                </button>
            </div>
        </div>
    );
}

export default function EducationPage() {
    return (
        <AuthGuard>
            <EducationContent />
        </AuthGuard>
    );
}

import type { Metadata } from "next";
import "./globals.css";
import ClientLayout from "@/components/layout/clientLayout";
import { ThemeProvider } from "@/components/theme-provider";

export const metadata: Metadata = {
  title: "Spear — Learn to Code",
  description: "Platform pembelajaran coding interaktif. Belajar HTML, CSS, JavaScript, dan PHP dengan animasi keren dan pelajaran bergamifikasi.",
  keywords: ["coding", "education", "HTML", "CSS", "JavaScript", "PHP", "learn programming", "spear"],
  other: {
    google: "notranslate",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="id" translate="no" className="notranslate" suppressHydrationWarning>
      <head>
        { }
        <meta name="google" content="notranslate" />
        <link
          href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap"
          rel="stylesheet"
        />
      </head>
      <body className="antialiased">
        <ThemeProvider attribute="class" defaultTheme="system" enableSystem>
          <ClientLayout>{children}</ClientLayout>
        </ThemeProvider>
      </body>
    </html>
  );
}

'use client';

import React, { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useParams, useRouter } from 'next/navigation';
import { curriculum, Slide } from '@/data/curriculum';
import { useAppStore, Language } from '@/store/useAppStore';
import FeedbackOverlay from '@/components/ui/feedbackOverlay';
import AuthGuard from '@/components/auth/authGuard';
import { CompanionExpression } from '@/components/illustrations/companionCharacter';
import { useSFXStore } from '@/store/useSFXStore';
import { sfx } from '@/lib/sfx';
import { Volume2, VolumeX, X } from 'lucide-react';

function LessonContent() {
    const params = useParams();
    const router = useRouter();
    const lang = params.lang as string;
    const levelId = params.levelId as string;

    const langData = curriculum[lang];
    const level = langData?.levels.find(l => l.id === levelId);

    const [currentSlide, setCurrentSlide] = useState(0);
    const [correctCount, setCorrectCount] = useState(0);
    const [showFeedback, setShowFeedback] = useState(false);
    const [feedbackCorrect, setFeedbackCorrect] = useState(false);
    const [feedbackExplanation, setFeedbackExplanation] = useState('');
    const [slideDirection, setSlideDirection] = useState(1);
    const [retryKey, setRetryKey] = useState(0);

    const [companionExpression, setCompanionExpression] = useState<CompanionExpression>('idle');
    const [companionMessage, setCompanionMessage] = useState<string>('Mari kita mulai!');

    const { enabled: sfxEnabled, toggleEnabled } = useSFXStore();

    const completeLevel = useAppStore(s => s.completeLevel);
    const trackFailedAnswer = useAppStore(s => s.trackFailedAnswer);

    if (!level || !langData) {
        return (
            <div className="text-center py-20">
                <h2 className="text-2xl font-bold">Lesson not found</h2>
                <button onClick={() => router.back()} className="text-primary mt-4 cursor-pointer">← Go back</button>
            </div>
        );
    }

    const slides = level.slides;
    const totalSlides = slides.length;
    const slide = slides[currentSlide];
    const progressPercent = ((currentSlide + 1) / totalSlides) * 100;

    // Set companion state on slide change
    React.useEffect(() => {
        if (!slide) return;
        if (slide.type === 'theory') {
            setCompanionExpression('idle');
            setCompanionMessage('Baca baik-baik ya');
        } else {
            setCompanionExpression('encouraging');
            setCompanionMessage('Kamu pasti bisa :3');
        }
    }, [currentSlide, slide]);

    const handleExerciseComplete = useCallback((isCorrect: boolean, explanation?: string) => {
        setFeedbackCorrect(isCorrect);
        setFeedbackExplanation(explanation || '');
        setShowFeedback(true);
        if (isCorrect) {
            setCorrectCount(prev => prev + 1);
            setCompanionExpression('celebrating');
            setCompanionMessage('Benar! Gacor King');
        } else {
            trackFailedAnswer(lang as Language);
            setCompanionExpression('sad');
            setCompanionMessage('Oops, coba lagi :<');
        }
    }, [lang, trackFailedAnswer]);

    const handleContinue = useCallback(() => {
        setShowFeedback(false);

        if (!feedbackCorrect) {
            // Wrong answer — increment retryKey to remount exercise with fresh state
            setRetryKey(prev => prev + 1);
            return;
        }

        if (currentSlide < totalSlides - 1) {
            setSlideDirection(1);
            setCurrentSlide(prev => prev + 1);
        } else {
            // Level complete!
            sfx.levelComplete();
            const score = Math.round((correctCount / (totalSlides - 1)) * 100); // exclude theory from scoring
            completeLevel(lang as Language, levelId, Math.min(100, score));
            router.push(`/learn/${lang}`);
        }
    }, [feedbackCorrect, currentSlide, totalSlides, correctCount, completeLevel, lang, levelId, router]);

    const handleNextTheory = useCallback(() => {
        if (currentSlide < totalSlides - 1) {
            setSlideDirection(1);
            setCurrentSlide(prev => prev + 1);
        }
    }, [currentSlide, totalSlides]);

    const langColors: Record<string, string> = {
        html: '#F06D5B',
        css: '#7EB8F0',
        js: '#F5C87A',
        php: '#9B8FE6',
    };
    const color = langColors[lang] || 'var(--color-primary)';

    return (
        <div className="max-w-xl mx-auto space-y-6">
            {/* Header */}
            <motion.div
                className="flex items-center gap-4"
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
            >
                <div className="flex gap-2">
                    <button
                        onClick={() => router.push(`/learn/${lang}`)}
                        title="Back to lessons"
                        className="w-10 h-10 rounded-xl glass flex items-center justify-center text-text-secondary hover:text-text cursor-pointer transition-colors"
                    >
                        <X size={20} />
                    </button>
                    <button
                        onClick={toggleEnabled}
                        title={sfxEnabled ? "Mute sound" : "Enable sound"}
                        className="w-10 h-10 rounded-xl glass flex items-center justify-center text-text-secondary hover:text-text cursor-pointer transition-colors"
                    >
                        {sfxEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
                    </button>
                </div>

                {/* Progress dots */}
                <div className="flex-1">
                    <div className="h-3 rounded-full overflow-hidden" style={{ background: 'rgba(0,0,0,0.06)' }}>
                        <motion.div
                            className="h-full rounded-full"
                            style={{ background: color }}
                            animate={{ width: `${progressPercent}%` }}
                            transition={{ duration: 0.5, ease: [0.25, 0.46, 0.45, 0.94] }}
                        />
                    </div>
                </div>

                <span className="text-sm font-semibold text-text-secondary">
                    {currentSlide + 1}/{totalSlides}
                </span>
            </motion.div>

            {/* Slide Content */}
            <AnimatePresence mode="wait" custom={slideDirection}>
                <motion.div
                    key={`${currentSlide}-${retryKey}`}
                    custom={slideDirection}
                    initial={{ opacity: 0, x: slideDirection * 40 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: slideDirection * -40 }}
                    transition={{ type: 'spring', stiffness: 300, damping: 28 }}
                >
                    <SlideContent
                        slide={slide}
                        color={color}
                        onComplete={handleExerciseComplete}
                        onNextTheory={handleNextTheory}
                        companionExpression={companionExpression}
                        companionMessage={companionMessage}
                    />
                </motion.div>
            </AnimatePresence>

            {/* Feedback Overlay */}
            <FeedbackOverlay
                show={showFeedback}
                isCorrect={feedbackCorrect}
                explanation={feedbackExplanation}
                onContinue={handleContinue}
            />
        </div>
    );
}

import SlideRenderer from '@/components/exercises/slideRenderer';

function SlideContent({
    slide,
    color,
    onComplete,
    onNextTheory,
    companionExpression,
    companionMessage,
}: {
    slide: Slide;
    color: string;
    onComplete: (isCorrect: boolean, explanation?: string) => void;
    onNextTheory: () => void;
    companionExpression: CompanionExpression;
    companionMessage?: string;
}) {
    return (
        <SlideRenderer
            slide={slide}
            color={color}
            onComplete={onComplete}
            onNextTheory={onNextTheory}
            companionExpression={companionExpression}
            companionMessage={companionMessage}
        />
    );
}

export default function LessonPage() {
    return (
        <AuthGuard>
            <LessonContent />
        </AuthGuard>
    );
}

'use client';

import React, { useEffect, useState, useRef, useCallback } from 'react';
import { motion, useInView, AnimatePresence, useScroll, useTransform, useSpring, useMotionValue, animate } from 'framer-motion';
import Link from 'next/link';
import dynamic from 'next/dynamic';
import { useAuthStore } from '@/store/useAuthStore';
import Footer from '@/components/layout/footer';
import ScrollProgress from '@/components/ui/scrollProgress';
import ParticleField from '@/components/ui/particleField';
import { HTMLMascot, CSSMascot, JSMascot, PHPMascot, StreakFire, BadgeIcon, SuccessIllustration } from '@/components/illustrations/mascots';
import { useIsMobile } from '@/hooks/useIsMobile';

const CodeEditor = dynamic(() => import('@/components/playground/codeEditor'), { ssr: false });
const LivePreview = dynamic(() => import('@/components/playground/livePreview'), { ssr: false });

/* ====== Reusable Scroll-Triggered Reveal ====== */
function SectionReveal({ children, className = '', delay = 0 }: { children: React.ReactNode; className?: string; delay?: number }) {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-80px' });
  const isMobile = useIsMobile();

  return (
    <motion.div
      ref={ref}
      className={className}
      initial={isMobile ? { opacity: 1, y: 0 } : { opacity: 0, y: 30, filter: 'blur(3px)' }}
      animate={isInView || isMobile ? { opacity: 1, y: 0, filter: 'blur(0px)' } : {}}
      transition={{ duration: 0.8, delay: isMobile ? 0 : delay, type: 'spring', stiffness: 80, damping: 20 }}
    >
      {children}
    </motion.div>
  );
}

/* ====== 3D Magnetic Tilt Card ====== */
function MagneticCard({ children, className = '' }: { children: React.ReactNode; className?: string }) {
  const ref = useRef<HTMLDivElement>(null);
  const isMobile = useIsMobile();
  const rotateX = useMotionValue(0);
  const rotateY = useMotionValue(0);
  const springX = useSpring(rotateX, { stiffness: 300, damping: 30 });
  const springY = useSpring(rotateY, { stiffness: 300, damping: 30 });

  const handleMouse = useCallback((e: React.MouseEvent) => {
    if (isMobile) return;
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    rotateX.set(y * -12);
    rotateY.set(x * 12);
  }, [rotateX, rotateY, isMobile]);

  const handleLeave = useCallback(() => {
    if (isMobile) return;
    rotateX.set(0);
    rotateY.set(0);
  }, [rotateX, rotateY, isMobile]);

  return (
    <motion.div
      ref={ref}
      className={className}
      style={isMobile ? {} : { rotateX: springX, rotateY: springY, transformPerspective: 800 }}
      onMouseMove={handleMouse}
      onMouseLeave={handleLeave}
    >
      {children}
    </motion.div>
  );
}

/* ====== Clean Typing Effect Text ====== */
function TypingText({ text, className = '', cursorColor = '#6DD5C4', delay = 0 }: { text: string; className?: string; cursorColor?: string; delay?: number }) {
  const [displayedText, setDisplayedText] = useState('');
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-50px' });
  const isMobile = useIsMobile();

  useEffect(() => {
    // On mobile, show text instantly to avoid animation overhead
    if (isMobile) {
      setDisplayedText(text);
      return;
    }
    if (!isInView) return;

    let i = 0;
    const timeoutId = setTimeout(() => {
      const intervalId = setInterval(() => {
        setDisplayedText(text.slice(0, i + 1));
        i++;
        if (i >= text.length) {
          clearInterval(intervalId);
        }
      }, 60); // typing speed
      return () => clearInterval(intervalId);
    }, delay * 1000);

    return () => clearTimeout(timeoutId);
  }, [isInView, text, delay, isMobile]);

  return (
    <span ref={ref} className={`inline-block ${className}`}>
      {displayedText}
      {!isMobile && (
        <motion.span
          className="inline-block w-[3px] h-[0.9em] align-middle ml-1 rounded-sm"
          style={{ backgroundColor: cursorColor }}
          animate={{ opacity: [1, 0] }}
          transition={{ repeat: Infinity, duration: 0.8, ease: 'linear' }}
        />
      )}
    </span>
  );
}

/* ====== Animated Counter ====== */
function AnimatedCounter({ target, suffix = '' }: { target: number; suffix?: string }) {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-20px' });
  const isMobile = useIsMobile();
  const count = useMotionValue(target); // Default to target instantly for mobile
  const rounded = useTransform(count, (latest) => Math.floor(latest) + suffix);

  useEffect(() => {
    if (isMobile) {
      count.set(target);
      return;
    }
    if (isInView) {
      count.set(0); // Reset for animation if desktop
      const controls = animate(count, target, { duration: 2, ease: "easeOut" });
      return controls.stop;
    }
  }, [isInView, target, count, isMobile]);

  return <motion.span ref={ref}>{rounded}</motion.span>;
}

