      {/* ====== FAQ ====== */}
      <section className="py-24 px-4 sm:px-6">
        <div className="max-w-3xl mx-auto">
          <SectionReveal className="text-center mb-16">
            <h2 className="text-3xl sm:text-5xl font-extrabold text-text mb-6 tracking-tight">
