          >
            <div className="relative z-10">
              <h2 className="text-3xl sm:text-5xl font-extrabold text-text mb-4 tracking-tight">
                Ready to <span className="text-gradient">Start</span>?
              </h2>
              <p className="text-base sm:text-lg text-text-secondary/90 mb-8 max-w-xl mx-auto leading-relaxed font-medium">
                Bergabunglah dengan ribuan developer lainnya. Mulai perjalanan coding kamu hari ini. Gratis selamanya, tanpa batasan.
              </p>

              <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <Link
                    href={ctaHref}
                    className="btn-shimmer cta-glow inline-flex w-full sm:w-auto items-center justify-center gap-2 px-8 py-4 rounded-xl font-bold text-white text-base shadow-lg shadow-primary/20"
                    style={{ background: 'linear-gradient(135deg, #6DD5C4, #7EB8F0)' }}
                  >
                    {isLoggedIn ? 'Buka Dashboard' : 'Daftar Sekarang — Gratis'}
                    <motion.svg
                      width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round"
                      animate={isMobile ? {} : { x: [0, 4, 0] }}
                      transition={isMobile ? {} : { duration: 1.5, repeat: Infinity, ease: "easeInOut" }}
                    >
                      <path d="M5 12H19M13 6L19 12L13 18" />
                    </motion.svg>
                  </Link>
                </motion.div>

                <motion.div whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}>
                  <Link
                    href="/playground"
                    className="inline-flex w-full sm:w-auto items-center justify-center gap-2 px-6 py-4 rounded-xl font-bold text-text bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 border-2 border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600 transition-all soft-shadow"
                  >
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
                      <polyline points="16 18 22 12 16 6" />
                      <polyline points="8 6 2 12 8 18" />
                    </svg>
                    Coba Playground
                  </Link>
                </motion.div>
              </div>
            </div>
          </motion.div>
        </div>
      </section>

      {/* ====== EMAIL / NEWSLETTER SECTION ====== */}
      <section className="py-20 px-4 sm:px-6 relative">
        <div className="max-w-3xl mx-auto">
          <motion.div
            className="glass-strong rounded-[32px] p-8 sm:p-14 soft-shadow-xl relative overflow-hidden bg-white/80"
            initial={{ opacity: 0, scale: 0.95, y: 30 }}
            whileInView={{ opacity: 1, scale: 1, y: 0 }}
            transition={{ type: "spring", bounce: 0.3 }}
            viewport={{ once: true }}
          >
            {/* Background accents */}
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
              {!isMobile && (
                <>
                  <motion.div
                    className="absolute -top-32 -left-32 w-64 h-64 rounded-full bg-primary/10 blur-3xl"
                    animate={{ x: [0, 50, 0], y: [0, 30, 0] }}
                    transition={{ duration: 15, repeat: Infinity, ease: "easeInOut" }}
                  />
                  <motion.div
                    className="absolute -bottom-32 -right-32 w-64 h-64 rounded-full bg-accent/10 blur-3xl"
                    animate={{ x: [0, -50, 0], y: [0, -30, 0] }}
                    transition={{ duration: 12, repeat: Infinity, ease: "easeInOut" }}
                  />
                </>
              )}
            </div>

            {/* Top animated gradient bar */}
            <div className="absolute top-0 left-0 right-0 h-1.5 animated-border border-0 border-b-0" />

            <div className="relative z-10">
              {/* Icon */}
              <motion.div
                className="w-16 h-16 rounded-2xl mx-auto mb-6 flex items-center justify-center shadow-md bg-white"
                initial={{ scale: 0, rotate: -20 }}
                whileInView={{ scale: 1, rotate: 0 }}
                transition={{ type: 'spring', stiffness: 400, damping: 12, delay: 0.2 }}
                viewport={{ once: true }}
              >
                <div className="w-12 h-12 rounded-xl flex items-center justify-center bg-gradient-to-br from-primary/20 to-accent/20">
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                    <rect x="2" y="4" width="20" height="16" rx="3" stroke="url(#mailGrad1)" strokeWidth="2.5" />
                    <path d="M2 7l10 6 10-6" stroke="url(#mailGrad1)" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
                    <defs>
                      <linearGradient id="mailGrad1" x1="2" y1="4" x2="22" y2="20">
                        <stop stopColor="#6DD5C4" />
                        <stop offset="1" stopColor="#7EB8F0" />
                      </linearGradient>
                    </defs>
                  </svg>
                </div>
              </motion.div>

              <h2 className="text-2xl sm:text-3xl font-extrabold text-text text-center mb-4 tracking-tight">
                Have a <span className="text-gradient">Question</span>?
              </h2>
              <p className="text-base text-text-secondary text-center mb-10 max-w-md mx-auto leading-relaxed">
                Hubungi kami kapan saja! Kirim pesan langsung ke tim Spear. Kami selalu senang mendengar feedback dari kamu.
              </p>

              <EmailForm />
            </div>
          </motion.div>
        </div>
      </section>

      <Footer />
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';
import { usePetStore, PetType } from '@/store/usePetStore';
import { sfx } from '@/lib/sfx';
import AuthGuard from '@/components/auth/authGuard';
import GlassCard from '@/components/ui/glassCard';
import { PetMascot, PetExpression } from '@/components/illustrations/petCharacters';
import { Sparkles, Moon, Sun } from 'lucide-react';
import PetSelection from '@/components/pet/petSelection';

const ACCESSORY_LIST = [
    {
        id: 'glasses',
        name: 'Kacamata Keren',
        icon: () => (
            <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
                <path d="M4 12h16M7 12a3 3 0 1 0 0-6 3 3 0 0 0 0 6zm10 0a3 3 0 1 0 0-6 3 3 0 0 0 0 6z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                <path d="M2 12l2-4m16 4l-2-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
        ),
        color: '#7EB8F0'
    },
    {
        id: 'hat',
        name: 'Topi Sihir',
        icon: () => (
            <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
                <path d="M12 4l-4 10h8l-4-10z" fill="currentColor" opacity="0.8" />
                <path d="M5 14h14v2H5v-2z" fill="currentColor" />
                <path d="M12 2l-5 12h10L12 2z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="none" />
                <path d="M4 14h16" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            </svg>
        ),
        color: '#9B8FE6'
    },
    {
        id: 'tie',
        name: 'Dasi Kupu-kupu',
        icon: () => (
            <svg viewBox="0 0 24 24" fill="none" className="w-6 h-6">
                <path d="M12 12l-5-4v8l5-4zm0 0l5-4v8l-5-4z" fill="currentColor" />
                <circle cx="12" cy="12" r="2" fill="white" />
            </svg>
        ),
        color: '#F06D5B'
    },
];

function PetContent() {
    const { selectedPet, petXP, getPetStage, equippedAccessories, toggleAccessory, showWanderingPet, setShowWanderingPet } = usePetStore();
    const [isSleeping, setIsSleeping] = useState(false);
    const [hearts, setHearts] = useState<{ id: number, x: number }[]>([]);
    const [petMessage, setPetMessage] = useState<string | null>(null);
    const [expression, setExpression] = useState<PetExpression>('idle');

    // Time Check Logic (WIB / UTC+7)
    useEffect(() => {
        const checkTimeWIB = () => {
            const now = new Date();
            const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
            const wibDate = new Date(utc + (3600000 * 7));
            const hours = wibDate.getHours();

            if (hours >= 22 || hours < 6) {
                setIsSleeping(true);
            } else {
                setIsSleeping(false);
            }
        };

        checkTimeWIB();
        const interval = setInterval(checkTimeWIB, 60000);
        return () => clearInterval(interval);
    }, []);

    // Random boredom if idle for 15 seconds
    useEffect(() => {
        if (isSleeping || expression !== 'idle') return;
        const timer = setTimeout(() => {
            const random = Math.random();
            if (random > 0.6) {
                setExpression('bored');
                setPetMessage('Hoaaamm...');
            }
        }, 15000);
        return () => clearTimeout(timer);
    }, [isSleeping, expression]);

    const interactPet = (action: 'feed' | 'play' | 'scold' | 'pet') => {
        if (isSleeping) return;

        if (action === 'pet') {
            sfx.petHappy();
            const uniqueId = Date.now() + Math.random();
            setHearts(prev => [...prev, { id: uniqueId, x: Math.random() * 40 - 20 }]);
            setPetMessage('❤️');
            setExpression('happy');
            setTimeout(() => setHearts(prev => prev.slice(1)), 1500);
        } else if (action === 'feed') {
            sfx.petHappy();
            setPetMessage('Nyam nyam! Enak!');
            setExpression('happy');
        } else if (action === 'play') {
            sfx.petHappy();
            setPetMessage('Yeyy! Main!!');
            setExpression('happy');
        } else if (action === 'scold') {
            const isAngry = Math.random() > 0.5;
            setExpression(isAngry ? 'angry' : 'sad');
            setPetMessage(isAngry ? 'Hmph!! Jangan marah!' : 'Maaf...');
        }

        // Reset back to idle after 4 seconds
        setTimeout(() => {
            setPetMessage(null);
            setExpression('idle');
        }, 4000);
    };

    if (!selectedPet) {
        return (
            <div className="max-w-2xl mx-auto space-y-6">
                <motion.div
                    className="flex items-center justify-between"
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                >
                    <Link
                        href="/education"
                        className="inline-flex items-center gap-2 px-4 py-2 rounded-[var(--radius-button)] glass soft-shadow text-sm font-medium text-text-secondary hover:text-text transition-colors"
                    >
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                            <path d="M19 12H5M12 19L5 12L12 5" />
                        </svg>
                        Back to Education
                    </Link>
                </motion.div>

                <PetSelection />
            </div>
        );
    }

    const stage = getPetStage();

    return (
        <div className="max-w-2xl mx-auto space-y-6">
            {/* Header / Nav */}
            <motion.div
                className="flex items-center justify-between"
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
            >
                <Link
                    href="/education"
                    className="inline-flex items-center gap-2 px-4 py-2 rounded-[var(--radius-button)] glass soft-shadow text-sm font-medium text-text-secondary hover:text-text transition-colors"
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                        <path d="M19 12H5M12 19L5 12L12 5" />
                    </svg>
                    Back to Education
                </Link>

                <div className="flex gap-2">
                    {/* Wandering Pet Toggle */}
                    <div className="px-4 py-2 glass rounded-full text-sm font-bold flex items-center gap-2 text-text-secondary cursor-pointer hover:bg-white/40 transition-colors" onClick={() => setShowWanderingPet(!showWanderingPet)}>
                        <span className="hidden sm:inline">Pet Berkeliaran</span>
                        <div
                            className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors ${showWanderingPet ? 'bg-primary' : 'bg-slate-300'}`}
                        >
                            <span
                                className={`inline-block h-3 w-3 transform rounded-full bg-white transition-transform ${showWanderingPet ? 'translate-x-5' : 'translate-x-1'}`}
                            />
                        </div>
                    </div>
                </div>
            </motion.div>

            {/* Pet Environment Area */}
            <motion.div
                className={`relative rounded-3xl overflow-hidden transition-colors duration-1000 ${isSleeping ? 'bg-indigo-950 shadow-[0_0_50px_rgba(30,27,75,0.8)_inset]' : 'bg-sky-100/50 glass shadow-[0_0_50px_rgba(255,255,255,0.5)_inset]'
                    }`}
                style={{ height: '350px' }}
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
            >
                {/* Environment Decor */}
                {isSleeping && (
                    <motion.div
                        className="absolute top-8 left-8 text-yellow-100 opacity-60"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 0.6 }}
                        transition={{ duration: 2 }}
                    >
                        <svg width="40" height="40" viewBox="0 0 24 24" fill="currentColor">
                            <path d="M12 21A9 9 0 1 1 21 12A8.995 8.995 0 0 0 12 21Z" />
                        </svg>
                    </motion.div>
                )}

                {/* Stars/Clouds */}
                <div className="absolute top-10 right-10 flex gap-4 opacity-50">
                    <motion.div animate={{ x: [-10, 10, -10] }} transition={{ duration: 8, repeat: Infinity, ease: 'linear' }} className={`w-16 h-4 rounded-full ${isSleeping ? 'bg-indigo-800' : 'bg-white'}`} />
                    <motion.div animate={{ x: [10, -10, 10] }} transition={{ duration: 12, repeat: Infinity, ease: 'linear' }} className={`w-24 h-5 rounded-full mt-4 ${isSleeping ? 'bg-indigo-800' : 'bg-white'}`} />
                </div>

                {/* Main Ground */}
                <div className={`absolute bottom-0 left-0 w-full h-32 transition-colors duration-1000 ${isSleeping ? 'bg-indigo-900 border-t border-indigo-800' : 'bg-emerald-100 border-t border-emerald-200'
                    }`} />

                {/* Interactive Pet */}
                <div className="absolute inset-x-0 bottom-10 flex flex-col justify-end items-center cursor-pointer group" onClick={() => interactPet('pet')}>
                    {/* Floating Hearts */}
                    <AnimatePresence>
                        {hearts.map(heart => (
                            <motion.div
                                key={heart.id}
                                className="absolute pointer-events-none z-20 text-error"
                                initial={{ opacity: 0, y: 0, scale: 0.5, x: heart.x }}
                                animate={{ opacity: [0, 1, 0], y: -80, scale: [0.5, 1.2, 1] }}
                                exit={{ opacity: 0 }}
                                transition={{ duration: 1.2, ease: "easeOut" }}
                            >
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor">
                                    <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z" />
                                </svg>
                            </motion.div>
                        ))}
                    </AnimatePresence>

                    <AnimatePresence>
                        {petMessage && (
                            <motion.div
                                className="absolute bottom-[220px] pointer-events-none z-30"
                                initial={{ opacity: 0, y: 10, scale: 0.5 }}
                                animate={{ opacity: [0, 1, 1, 0], y: -15, scale: 1 }}
                                exit={{ opacity: 0 }}
                                transition={{ duration: 2.5, times: [0, 0.1, 0.9, 1] }}
                            >
                                {petMessage === '❤️' ? (
                                    <span className="text-4xl filter drop-shadow-md">❤️</span>
                                ) : (
                                    <div className="glass-strong text-text font-bold text-sm md:text-base px-5 py-3 rounded-2xl soft-shadow text-center relative max-w-[200px]">
                                        {petMessage}
                                        {/* Tail */}
                                        <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 border-[6px] border-transparent border-t-white/80 filter drop-shadow-sm" />
                                    </div>
                                )}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    <motion.div whileHover={isSleeping ? undefined : { scale: 1.05 }} whileTap={isSleeping ? undefined : { scale: 0.95 }}>
                        <PetMascot
                            pet={selectedPet}
                            stage={stage}
                            size={160}
                            isSleeping={isSleeping}
                            expression={expression}
                            accessories={equippedAccessories}
                        />
                    </motion.div>

                    {/* Shadow underneath */}
                    <motion.div
                        className="w-24 h-4 rounded-[100%] bg-black/20 mt-1 blur-sm"
                        animate={isSleeping ? { scaleX: [1, 0.9, 1] } : { scaleX: [1, 1.1, 1], opacity: [0.2, 0.1, 0.2] }}
                        transition={{ duration: isSleeping ? 4 : 2.5, repeat: Infinity }}
                    />
                </div>
            </motion.div>

            {/* Info and Shop/Wardrobe */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Interactions */}
                <GlassCard>
                    <h3 className="text-lg font-bold text-text mb-4">Interaksi</h3>
                    <div className="flex gap-3">
                        <button onClick={() => interactPet('feed')} className="flex-1 py-3 px-4 glass rounded-xl hover:bg-white/40 transition-colors font-semibold text-text text-sm">
                            Beri Makan
                        </button>
                        <button onClick={() => interactPet('play')} className="flex-1 py-3 px-4 glass rounded-xl hover:bg-white/40 transition-colors font-semibold text-text text-sm">
                            Ajak Main
                        </button>
                        <button onClick={() => interactPet('scold')} className="flex-1 py-3 px-4 glass rounded-xl hover:bg-white/40 border border-error/20 transition-colors font-semibold text-error text-sm">
                            Tegur
                        </button>
                    </div>
                </GlassCard>

                {/* Stars/XP (Moved from a separate stat block) */}
                <GlassCard>
                    <h3 className="text-lg font-bold text-text mb-4">Status Pertumbuhan</h3>
                    <div className="space-y-4">
                        <div>
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-text-secondary font-medium">Pengalaman (XP)</span>
                                <span className="font-bold text-primary">{petXP} XP</span>
                            </div>
                            <div className="h-3 rounded-full bg-slate-100 overflow-hidden">
                                <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${Math.min(100, (petXP / 500) * 100)}%` }} />
                            </div>
                        </div>
                        <div className="flex justify-between text-sm">
                            <span className="text-text-secondary font-medium">Tahap Pertumbuhan</span>
                            <span className="font-bold capitalize text-primary">{stage}</span>
                        </div>
                    </div>
                </GlassCard>

                {/* Accessories Wardrobe */}
                <GlassCard className="md:col-span-2">
                    <h3 className="text-lg font-bold text-text mb-4">Lemari Aksesoris</h3>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                        {ACCESSORY_LIST.map((acc) => {
                            const isEquipped = equippedAccessories.includes(acc.id);
                            return (
                                <button
                                    key={acc.id}
                                    onClick={() => toggleAccessory(acc.id)}
                                    className={`relative p-3 rounded-xl border-2 transition-all flex flex-col items-center gap-2 cursor-pointer ${isEquipped
                                        ? 'border-primary bg-primary/10'
                                        : 'border-transparent bg-slate-100 hover:bg-slate-200 dark:bg-slate-800/80 dark:hover:bg-slate-700'
                                        }`}
                                >
                                    <div
                                        className="w-10 h-10 rounded-full flex items-center justify-center text-white"
                                        style={{ background: acc.color }}
                                    >
                                        <acc.icon />
                                    </div>
                                    <span className="text-xs font-bold text-text text-center">{acc.name}</span>

                                    {isEquipped && (
                                        <div className="absolute -top-2 -right-2 w-6 h-6 bg-primary rounded-full flex items-center justify-center border-2 border-white">
                                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3" strokeLinecap="round">
                                                <path d="M20 6L9 17L4 12" />
                                            </svg>
                                        </div>
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </GlassCard>
            </div>
        </div>
    );
}

export default function PetPage() {
    return (
        <AuthGuard>
            <PetContent />
        </AuthGuard>
    );
}

'use client';

import React, { useState, Suspense, useCallback, useMemo } from 'react';
import { useSearchParams } from 'next/navigation';
import { motion } from 'framer-motion';
import Link from 'next/link';
import dynamic from 'next/dynamic';
import SpearLogo from '@/components/ui/spearLogo';

const CodeEditor = dynamic(() => import('@/components/playground/codeEditor'), { ssr: false });
const LivePreview = dynamic(() => import('@/components/playground/livePreview'), { ssr: false });

const presets: Record<string, { html: string; css: string; js: string }> = {
    html: {
        html: `<h1>Hello World</h1>\n<p>Welcome to <strong>Spear Code Editor</strong>.</p>\n<p>Edit code ini dan lihat perubahan yang instan</p>\n\n<ul>\n  <li>HTML untuk structure</li>\n  <li>CSS untuk styling</li>\n  <li>JavaScript untuk logic</li>\n</ul>`,
        css: '',
        js: '',
    },
    css: {
        html: `<div class="card">\n  <h2>Styled Card</h2>\n  <p>This card is styled with CSS</p>\n  <button class="btn">Click Me</button>\n</div>`,
        css: `.card {\n  max-width: 320px;\n  padding: 24px;\n  border-radius: 16px;\n  background: linear-gradient(135deg, #667eea, #764ba2);\n  color: white;\n  font-family: sans-serif;\n  box-shadow: 0 10px 40px rgba(102, 126, 234, 0.3);\n}\n\n.card h2 {\n  margin: 0 0 8px;\n}\n\n.card p {\n  opacity: 0.9;\n  margin: 0 0 16px;\n}\n\n.btn {\n  padding: 10px 24px;\n  border: 2px solid white;\n  border-radius: 99px;\n  background: transparent;\n  color: white;\n  font-weight: bold;\n  cursor: pointer;\n  transition: all 0.2s;\n}\n\n.btn:hover {\n  background: white;\n  color: #764ba2;\n}`,
        js: '',
    },
    js: {
        html: `<h2 id="title">Counter App</h2>\n<p>Count: <span id="count">0</span></p>\n<button id="increment" style="padding:8px 20px;border-radius:8px;border:none;background:#6DD5C4;color:white;font-weight:bold;cursor:pointer;margin-right:8px">+1</button>\n<button id="decrement" style="padding:8px 20px;border-radius:8px;border:none;background:#F06D5B;color:white;font-weight:bold;cursor:pointer">-1</button>`,
        css: '',
        js: `let count = 0;\nconst countEl = document.getElementById('count');\n\ndocument.getElementById('increment').addEventListener('click', () => {\n  count++;\n  countEl.textContent = count;\n});\n\ndocument.getElementById('decrement').addEventListener('click', () => {\n  count--;\n  countEl.textContent = count;\n});`,
    },
    php: {
        html: `<?php\n// PHP code runs on a server, not in the browser.\n// Use this editor to practice PHP syntax!\n\n$greeting = "Hello from PHP!";\n$items = ["HTML", "CSS", "JavaScript", "PHP"];\n\necho "<h1>$greeting</h1>";\necho "<ul>";\nforeach ($items as $item) {\n    echo "<li>$item</li>";\n}\necho "</ul>";\n\n// Variables & Types\n$name = "Spear";\n$version = 2.0;\n$isAwesome = true;\n\necho "<p>$name v$version is awesome: " . ($isAwesome ? 'Yes!' : 'No') . "</p>";\n?>`,
        css: '',
        js: '',
    },
};

const langIcons: Record<string, { color: string; label: string; shortLabel: string }> = {
    html: { color: '#F06D5B', label: 'HTML', shortLabel: 'HTML' },
    css: { color: '#7EB8F0', label: 'CSS', shortLabel: 'CSS' },
    js: { color: '#F5C87A', label: 'JavaScript', shortLabel: 'JS' },
    php: { color: '#9B8FE6', label: 'PHP', shortLabel: 'PHP' },
};
/**
 * Prettify CSS: expand single-line rules into multi-line.
 */
function prettifyCSSRules(raw: string): string {
    return raw.replace(
        /([^{}@\n][^{}]*?)\s*\{([^{}]+)\}/g,
        (_: string, sel: string, body: string) => {
            const s = sel.trim();
            if (!s) return _;
            const props = body.split(';')
                .map((p: string) => p.trim())
                .filter((p: string) => p.length > 0)
                .map((p: string) => `  ${p};`)
                .join('\n');
            return `${s} {\n${props}\n}`;
        }
    );
}

/**
 * Split a combined code example into separate html/css/js parts
 * for the playground tabs (index.html / style.css / script.js).
 * Also extracts inline style="" attributes into CSS classes.
 */
function splitCodeForPlayground(code: string): { html: string; css: string; js: string } {
    let html = code;
    let cssparts: string[] = [];
    let js = '';

    // 1) Extract <style> blocks → css tab
    const styleMatches = html.match(/<style>([\s\S]*?)<\/style>/gi);
    if (styleMatches) {
        const raw = styleMatches
            .map(m => m.replace(/<\/?style>/gi, '').trim())
            .join('\n\n')
            .trim();
        cssparts.push(prettifyCSSRules(raw));
        html = html.replace(/<style>[\s\S]*?<\/style>/gi, '').trim();
    }

    // 2) Extract <script> blocks → js tab
    const scriptMatches = html.match(/<script>([\s\S]*?)<\/script>/gi);
    if (scriptMatches) {
        js = scriptMatches
            .map(m => m.replace(/<\/?script>/gi, '').trim())
            .join('\n\n')
            .trim();
        html = html.replace(/<script>[\s\S]*?<\/script>/gi, '').trim();
    }

    // 3) Extract inline style="..." → generate CSS classes
    let counter = 0;
    const styleToClass = new Map<string, string>();

    // Pass 1: replace style="..." with a temp marker
    html = html.replace(/ style="([^"]*)"/g, (_, styleVal: string) => {
        let cls = styleToClass.get(styleVal);
        if (!cls) {
            counter++;
            cls = `s${counter}`;
            styleToClass.set(styleVal, cls);
        }
        return ` data-sc="${cls}"`;
    });

    // Pass 2: merge data-sc into existing class or create new class attr
    html = html.replace(/ data-sc="(\w+)"/g, (marker, cls) => {
        return ` class="${cls}"`;
    });
    // Handle elements that now have two class attrs: merge them
    html = html.replace(/ class="([^"]*)" class="([^"]*)"/g, (_, c1, c2) => {
        return ` class="${c1} ${c2}"`;
    });

    // Generate CSS from inline styles
    if (styleToClass.size > 0) {
        const lines: string[] = [];
        for (const [styleVal, cls] of styleToClass) {
            const props = styleVal.split(';')
                .map((p: string) => p.trim())
                .filter((p: string) => p.length > 0)
                .map((p: string) => `  ${p};`)
                .join('\n');
            lines.push(`.${cls} {\n${props}\n}`);
        }
        cssparts.push(lines.join('\n\n'));
    }

    // Combine all CSS
    const css = cssparts.filter(Boolean).join('\n\n');

    // Clean up HTML (put tags on separate lines)
    html = html.replace(/>\s*</g, '>\n<').trim();

    return { html, css, js };
}

function PlaygroundContent() {
    const searchParams = useSearchParams();
    const initialLang = searchParams.get('lang') || 'html';
    const initialCode = searchParams.get('code');

    const [activeLang, setActiveLang] = useState(initialLang);
    const [codes, setCodes] = useState(() => {
        const base = { ...presets[initialLang] || presets.html };
        if (initialCode) {
            let decoded: string;
            try {
                decoded = decodeURIComponent(initialCode);
            } catch {
                decoded = initialCode;
            }
            const split = splitCodeForPlayground(decoded);
            base.html = split.html;
            base.css = split.css;
            base.js = split.js;
        }
        return base;
    });
    const [activeEditor, setActiveEditor] = useState<'html' | 'css' | 'js'>('html');
    const [mobileView, setMobileView] = useState<'editor' | 'preview'>('editor');

    const isPhp = activeLang === 'php';

    const handleLangSwitch = useCallback((lang: string) => {
        setActiveLang(lang);
        setCodes(presets[lang] || presets.html);
        setActiveEditor('html');
        setMobileView('editor');
    }, []);

    const handleCodeChange = useCallback((value: string) => {
        setCodes((prev) => ({ ...prev, [activeEditor]: value }));
    }, [activeEditor]);

    const currentCode = useMemo(() => codes[activeEditor], [codes, activeEditor]);
    const editorLang = useMemo(() => {
        if (isPhp && activeEditor === 'html') return 'php';
        return activeEditor;
    }, [isPhp, activeEditor]);

    return (
        <div className="min-h-[100dvh] flex flex-col">
            {/* Header */}
            <div className="glass-strong border-b border-white/10 px-3 sm:px-6 py-2.5 sm:py-3">
                <div className="max-w-[1400px] mx-auto flex items-center justify-between gap-2">
